"""
Represents the game board and its pieces.
"""

class Piece:
    def __init__(self, owner):
        self.owner = owner

class Board:
    def __init__(self):
        self.grid = [[None for _ in range(8)] for _ in range(8)]
        self.current_player = 'white'

    def setup(self):
        # Initial board setup with pieces
        for row in range(3):
            for col in range(row % 2, 8, 2):
                self.grid[row][col] = Piece('white')
        for row in range(5, 8):
            for col in range((row + 1) % 2, 8, 2):
                self.grid[row][col] = Piece('black')

    def is_valid_move(self, move):
        # Simple validation (needs full implementation)
        return True

    def make_move(self, move):
        if self.is_valid_move(move):
            # Logic to make the move
            return True
        return False

    def is_game_over(self):
        # Logic to check game over conditions
        return False

    def __str__(self):
        board_str = ""
        for row in self.grid:
            board_str += " ".join(piece.owner if piece else "." for piece in row) + "\n"
        return board_str

class CheckersGame:
    def __init__(self):
        self.board = Board()
        self.board.setup()

    def make_move(self, move):
        return self.board.make_move(move)

    @property
    def current_player(self):
        return self.board.current_player

    def is_game_over(self):
        return self.board.is_game_over()
```

